class IntArray {
    int* m_data{};
    int m_length{};
public:
    IntArray(int length) : m_length{length} {
        m_data = new int[length]{};
    }
    ~IntArray() {
        delete[] m_data;  // Container manages lifetime
    }
};

class PlayerGroup {
    std::vector&lt;Player*&gt; m_players;
public:
    void addPlayer(Player* player) {
        m_players.push_back(player);
    }
    // No deletion in destructor - players managed elsewhere
};
